sql:
SELECT s.student_name, a.award
FROM students s
JOIN achievements a ON s.student_id = a.student_id;

SELECT achievement_type, award, date_of_achievement
FROM achievements
ORDER BY date_of_achievement DESC;

external_knowledge:
- Each achievement may belong to a certain category with a hierarchy structure;
- 'Hierarchy level' refers to the depth of the category within a category tree;
- Category details include the name, description, creation time, and update time of the category.

sql:
SELECT COUNT(*) AS TotalMedals
FROM achievements
WHERE achievement_type LIKE '%Medal%';

external_knowledge:
- International level achievements are of higher significance than national or local levels;
- Proof of achievement can be a document or URL, confirming the medal won;
- The category highlights the field in which the student excelled (e.g., sports, academics).

sql:
SELECT AVG(achievement_count) AS average_achievements
FROM (
    SELECT student_id, COUNT(achievement_id) AS achievement_count
    FROM achievements
    GROUP BY student_id
) AS student_achievements;
